import React from 'react';
import { FormWizard } from './FormWizard';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Form Wizard</h1>
      <FormWizard />
    </div>
  );
}

import React, { useReducer, useCallback } from 'react';
import './styles.css';

// --- Types ---
interface PersonalData {
  name: string;
  email: string;
}

interface AddressData {
  street: string;
  city: string;
  zip: string;
}

interface FormState {
  currentStep: number;
  steps: {
    personal: PersonalData;
    address: AddressData;
  };
  errors: Record<string, string>;
  visited: boolean[];
  submitted: boolean;
}

type FormAction =
  | { type: 'SET_FIELD'; step: 'personal' | 'address'; field: string; value: string }
  | { type: 'NEXT_STEP' }
  | { type: 'PREV_STEP' }
  | { type: 'GO_TO_STEP'; step: number }
  | { type: 'VALIDATE_STEP' }
  | { type: 'SUBMIT' };

const initialState: FormState = {
  currentStep: 0,
  steps: {
    personal: { name: '', email: '' },
    address: { street: '', city: '', zip: '' },
  },
  errors: {},
  visited: [true, false, false],
  submitted: false,
};

// --- Validation ---
// TODO: Implement validateStep that returns Record<string, string>
// Step 0 (personal): name required min 2 chars, email required and must contain @
// Step 1 (address): street required, city required, zip required and exactly 5 digits
