  return errors;
}

// --- Reducer ---
// TODO: Implement formReducer
export function formReducer(state: FormState, action: FormAction): FormState {
  switch (action.type) {
    case 'SET_FIELD':
      // TODO: Update the field and clear its error
      return state;
    case 'NEXT_STEP': {
      // TODO: Validate current step; if valid, advance and mark visited
      return state;
    }
    case 'PREV_STEP':
      // TODO: Go back one step (no validation)
      return state;
    case 'GO_TO_STEP':
      // TODO: Jump to step if visited
      return state;
    case 'SUBMIT': {
      // TODO: Validate step 1 (address); if valid, set submitted=true
