  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.wizard__error {
  font-size: 0.75rem;
  color: #dc2626;
}

.wizard__review h3 {
  margin: 0 0 0.75rem;
  font-size: 1rem;
}

.wizard__review dl {
  display: grid;
  grid-template-columns: 5rem 1fr;
  gap: 0.5rem;
  font-size: 0.875rem;
}

.wizard__review dt {
  color: #6b7280;
  font-weight: 500;
}

.wizard__review dd {
  margin: 0;
}

.wizard__nav {
  display: flex;
  gap: 0.5rem;
  justify-content: flex-end;
}

.btn {
  padding: 0.5rem 1.25rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
  font-weight: 500;
}

.btn--primary {
  background: #3b82f6;
  border-color: #3b82f6;
  color: white;
}

.btn--primary:hover {
  background: #2563eb;
}

.wizard__success {
  text-align: center;
  padding: 2rem;
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  border-radius: 0.5rem;
}

.wizard__success h2 {
  color: #166534;
  margin: 0 0 0.75rem;
}

.wizard__success p {
  margin: 0.25rem 0;
  color: #374151;
  font-size: 0.875rem;
}

