import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { formReducer } from './FormWizard';

const initial = {
  currentStep: 0,
  steps: {
    personal: { name: '', email: '' },
    address: { street: '', city: '', zip: '' },
  },
  errors: {},
  visited: [true, false, false],
  submitted: false,
};

describe('formReducer', () => {
  it('sets a field value', () => {
    const result = formReducer(initial, { type: 'SET_FIELD', step: 'personal', field: 'name', value: 'Alice' });
    expect(result.steps.personal.name).toBe('Alice');
  });

  it('clears field error on SET_FIELD', () => {
    const withErrors = { ...initial, errors: { name: 'Required' } };
    const result = formReducer(withErrors, { type: 'SET_FIELD', step: 'personal', field: 'name', value: 'Al' });
    expect(result.errors.name).toBeUndefined();
  });

  it('blocks NEXT_STEP with empty fields', () => {
    const result = formReducer(initial, { type: 'NEXT_STEP' });
    expect(result.currentStep).toBe(0);
    expect(Object.keys(result.errors).length).toBeGreaterThan(0);
  });

  it('goes back without validation', () => {
    const atStep1 = { ...initial, currentStep: 1, visited: [true, true, false] };
    const result = formReducer(atStep1, { type: 'PREV_STEP' });
    expect(result.currentStep).toBe(0);
  });
});

describe('FormWizard integration', () => {
  function renderWizard() {
    const { FormWizard } = require('./FormWizard');
    render(<FormWizard />);
  }

  it('starts at step 1', () => {
    renderWizard();
    expect(screen.getByTestId('current-step')).toHaveTextContent('Step 1 of 3');
  });

  it('shows validation errors when clicking Next with empty fields', () => {
    renderWizard();
    fireEvent.click(screen.getByTestId('next-btn'));
    expect(screen.getByTestId('error-name')).toBeInTheDocument();
    expect(screen.getByTestId('error-email')).toBeInTheDocument();
  });

  it('advances to step 2 with valid personal info', () => {
    renderWizard();
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.change(screen.getByTestId('field-email'), { target: { value: 'alice@test.com' } });
    fireEvent.click(screen.getByTestId('next-btn'));
    expect(screen.getByTestId('current-step')).toHaveTextContent('Step 2 of 3');
  });

  it('validates zip as 5 digits', () => {
    renderWizard();
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.change(screen.getByTestId('field-email'), { target: { value: 'alice@test.com' } });
    fireEvent.click(screen.getByTestId('next-btn'));
    fireEvent.change(screen.getByTestId('field-street'), { target: { value: '123 Main St' } });
    fireEvent.change(screen.getByTestId('field-city'), { target: { value: 'Portland' } });
    fireEvent.change(screen.getByTestId('field-zip'), { target: { value: 'abc' } });
    fireEvent.click(screen.getByTestId('next-btn'));
    expect(screen.getByTestId('error-zip')).toBeInTheDocument();
  });

  it('submits successfully after all steps', () => {
    renderWizard();
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.change(screen.getByTestId('field-email'), { target: { value: 'alice@test.com' } });
    fireEvent.click(screen.getByTestId('next-btn'));
    fireEvent.change(screen.getByTestId('field-street'), { target: { value: '123 Main St' } });
    fireEvent.change(screen.getByTestId('field-city'), { target: { value: 'Portland' } });
    fireEvent.change(screen.getByTestId('field-zip'), { target: { value: '97201' } });
    fireEvent.click(screen.getByTestId('next-btn'));
    fireEvent.click(screen.getByTestId('submit-btn'));
    expect(screen.getByTestId('success-msg')).toBeInTheDocument();
  });
});

