import React, { useReducer } from 'react';
import './styles.css';

interface PersonalData {
  name: string;
  email: string;
}

interface AddressData {
  street: string;
  city: string;
  zip: string;
}

interface FormState {
  currentStep: number;
  steps: {
    personal: PersonalData;
    address: AddressData;
  };
  errors: Record<string, string>;
  visited: boolean[];
  submitted: boolean;
}

type FormAction =
  | { type: 'SET_FIELD'; step: 'personal' | 'address'; field: string; value: string }
  | { type: 'NEXT_STEP' }
  | { type: 'PREV_STEP' }
  | { type: 'GO_TO_STEP'; step: number }
  | { type: 'VALIDATE_STEP' }
  | { type: 'SUBMIT' };

const initialState: FormState = {
  currentStep: 0,
  steps: {
    personal: { name: '', email: '' },
    address: { street: '', city: '', zip: '' },
  },
  errors: {},
  visited: [true, false, false],
  submitted: false,
};

function validateStep(step: number, data: FormState['steps']): Record<string, string> {
  const errors: Record<string, string> = {};
  if (step === 0) {
    if (!data.personal.name || data.personal.name.length < 2) errors.name = 'Name must be at least 2 characters';
    if (!data.personal.email || !data.personal.email.includes('@')) errors.email = 'Valid email is required';
  } else if (step === 1) {
    if (!data.address.street) errors.street = 'Street is required';
    if (!data.address.city) errors.city = 'City is required';
    if (!data.address.zip || !/^\d{5}$/.test(data.address.zip)) errors.zip = 'Zip must be exactly 5 digits';
  }
  return errors;
}

export function formReducer(state: FormState, action: FormAction): FormState {
  switch (action.type) {
    case 'SET_FIELD': {
      const { step, field, value } = action;
      const newErrors = { ...state.errors };
      delete newErrors[field];
      return {
        ...state,
        steps: {
          ...state.steps,
          [step]: { ...state.steps[step], [field]: value },
        },
        errors: newErrors,
      };
    }
    case 'NEXT_STEP': {
      const errors = validateStep(state.currentStep, state.steps);
      if (Object.keys(errors).length > 0) {
        return { ...state, errors };
      }
      const nextStep = state.currentStep + 1;
      const visited = [...state.visited];
      visited[nextStep] = true;
      return { ...state, currentStep: nextStep, errors: {}, visited };
    }
    case 'PREV_STEP':
      return { ...state, currentStep: Math.max(0, state.currentStep - 1) };
    case 'GO_TO_STEP':
      if (!state.visited[action.step]) return state;
      return { ...state, currentStep: action.step };
    case 'SUBMIT': {
      const errors = validateStep(1, state.steps);
      if (Object.keys(errors).length > 0) {
        return { ...state, errors };
      }
      return { ...state, submitted: true };
    }
    default:
      return state;
  }
}

export const FormWizard: React.FC = () => {
  const [state, dispatch] = useReducer(formReducer, initialState);
  const { currentStep, steps, errors, visited, submitted } = state;

  const setField = (step: 'personal' | 'address', field: string, value: string) =>
    dispatch({ type: 'SET_FIELD', step, field, value });

  if (submitted) {
    return (
      <div className="wizard__success" data-testid="success-msg">
        <h2>✓ Form Submitted!</h2>
        <p>{steps.personal.name} ({steps.personal.email})</p>
        <p>{steps.address.street}, {steps.address.city} {steps.address.zip}</p>
      </div>
    );
  }

  return (
    <div className="wizard">
      <div className="wizard__steps">
        {['Personal', 'Address', 'Review'].map((label, i) => (
          <button
            key={i}
            data-testid={`step-${i}`}
            className={`wizard__step${currentStep === i ? ' wizard__step--active' : ''}${visited[i] ? ' wizard__step--visited' : ''}`}
            onClick={() => dispatch({ type: 'GO_TO_STEP', step: i })}
            disabled={!visited[i]}
          >
            {label}
          </button>
        ))}
      </div>
      <p data-testid="current-step" className="wizard__current">Step {currentStep + 1} of 3</p>

      {currentStep === 0 && (
        <div className="wizard__fields">
          <div className="wizard__field">
            <label>Name</label>
            <input data-testid="field-name" value={steps.personal.name} onChange={e => setField('personal', 'name', e.target.value)} />
            {errors.name && <span data-testid="error-name" className="wizard__error">{errors.name}</span>}
          </div>
          <div className="wizard__field">
            <label>Email</label>
            <input data-testid="field-email" value={steps.personal.email} onChange={e => setField('personal', 'email', e.target.value)} />
            {errors.email && <span data-testid="error-email" className="wizard__error">{errors.email}</span>}
          </div>
        </div>
      )}

      {currentStep === 1 && (
        <div className="wizard__fields">
          <div className="wizard__field">
            <label>Street</label>
            <input data-testid="field-street" value={steps.address.street} onChange={e => setField('address', 'street', e.target.value)} />
            {errors.street && <span data-testid="error-street" className="wizard__error">{errors.street}</span>}
          </div>
          <div className="wizard__field">
            <label>City</label>
            <input data-testid="field-city" value={steps.address.city} onChange={e => setField('address', 'city', e.target.value)} />
            {errors.city && <span data-testid="error-city" className="wizard__error">{errors.city}</span>}
          </div>
          <div className="wizard__field">
            <label>Zip</label>
            <input data-testid="field-zip" value={steps.address.zip} onChange={e => setField('address', 'zip', e.target.value)} />
            {errors.zip && <span data-testid="error-zip" className="wizard__error">{errors.zip}</span>}
          </div>
        </div>
      )}

      {currentStep === 2 && (
        <div className="wizard__review">
          <h3>Review Your Info</h3>
          <dl>
            <dt>Name</dt><dd>{steps.personal.name}</dd>
            <dt>Email</dt><dd>{steps.personal.email}</dd>
            <dt>Street</dt><dd>{steps.address.street}</dd>
            <dt>City</dt><dd>{steps.address.city}</dd>
            <dt>Zip</dt><dd>{steps.address.zip}</dd>
          </dl>
        </div>
      )}

      <div className="wizard__nav">
        {currentStep > 0 && (
          <button data-testid="back-btn" className="btn" onClick={() => dispatch({ type: 'PREV_STEP' })}>Back</button>
        )}
        {currentStep < 2 && (
          <button data-testid="next-btn" className="btn btn--primary" onClick={() => dispatch({ type: 'NEXT_STEP' })}>Next</button>
        )}
        {currentStep === 2 && (
          <button data-testid="submit-btn" className="btn btn--primary" onClick={() => dispatch({ type: 'SUBMIT' })}>Submit</button>
        )}
      </div>
    </div>
  );
};
